INSERT INTO items (domain, subdomain, age_bands, difficulty, discrimination, guessing, content_json) VALUES
('reasoning', 'analogies', '{6-8}', -0.5, 1.2, 0.25, '{"stem": "Democracy is to government as capitalism is to ___", "type": "analogy", "options": [{"text": "Politics"}, {"text": "Economics"}, {"text": "Society"}, {"text": "Law"}], "correct_index": 1}'),
