('reasoning', 'analogies', '{6-8}', 0.5, 1.4, 0.20, '{"stem": "Symphony is to composer as novel is to ___", "type": "analogy", "options": [{"text": "Reader"}, {"text": "Publisher"}, {"text": "Author"}, {"text": "Editor"}], "correct_index": 2}'),
