('reasoning', 'classification', '{6-8}', 1.0, 1.5, 0.20, '{"stem": "Which does NOT belong? Simile, Metaphor, Hypothesis, Personification", "type": "odd_one_out", "options": [{"text": "Simile"}, {"text": "Metaphor"}, {"text": "Hypothesis"}, {"text": "Personification"}], "correct_index": 2}'),
('reasoning', 'series', '{6-8}', 0.5, 1.3, 0.20, '{"stem": "What comes next? 1, 4, 9, 16, 25, ___", "type": "number_series", "options": [{"text": "30"}, {"text": "36"}, {"text": "49"}, {"text": "32"}], "correct_index": 1}'),
('reasoning', 'series', '{6-8}', 1.0, 1.5, 0.20, '{"stem": "What comes next? 1, 1, 2, 3, 5, 8, 13, ___", "type": "number_series", "options": [{"text": "18"}, {"text": "20"}, {"text": "21"}, {"text": "26"}], "correct_index": 2}'),
('reasoning', 'series', '{6-8}', 1.5, 1.7, 0.15, '{"stem": "What comes next? 2, 6, 12, 20, 30, ___", "type": "number_series", "options": [{"text": "40"}, {"text": "42"}, {"text": "36"}, {"text": "48"}], "correct_index": 1}'),
('reasoning', 'logical', '{6-8}', 1.0, 1.5, 0.20, '{"stem": "All integers divisible by 6 are divisible by 3. 24 is divisible by 6. Which must be true?", "type": "syllogism", "options": [{"text": "24 is divisible by 3"}, {"text": "24 is divisible by 9"}, {"text": "All numbers divisible by 3 are divisible by 6"}, {"text": "24 is prime"}], "correct_index": 0}'),
('reasoning', 'logical', '{6-8}', 1.5, 1.7, 0.15, '{"stem": "If A implies B, and B implies C, what can we conclude?", "type": "syllogism", "options": [{"text": "C implies A"}, {"text": "A implies C"}, {"text": "Not A implies not C"}, {"text": "B implies A"}], "correct_index": 1}'),
('reasoning', 'logical', '{6-8}', 2.0, 1.8, 0.15, '{"stem": "Some artists are musicians. All musicians practice daily. Which MUST be true?", "type": "syllogism", "options": [{"text": "All artists practice daily"}, {"text": "Some artists practice daily"}, {"text": "All who practice daily are musicians"}, {"text": "No artists practice daily"}], "correct_index": 1}'),
('reasoning', 'analogies', '{6-8}', 2.5, 2.0, 0.15, '{"stem": "Entropy is to thermodynamics as natural selection is to ___", "type": "analogy", "options": [{"text": "Genetics"}, {"text": "Evolution"}, {"text": "Ecology"}, {"text": "Taxonomy"}], "correct_index": 1}'),
