('math', 'problem_solving', '{6-8}', 2.5, 1.9, 0.15, '{"stem": "The probability of rain on any given day is 0.3. What is the probability of NO rain for 3 consecutive days?", "type": "probability", "options": [{"text": "0.343"}, {"text": "0.027"}, {"text": "0.7"}, {"text": "0.9"}], "correct_index": 0}'),
